<?php $c=current_customer(); $rows=[]; $flash=get_flash(); try{$st=db()->prepare('SELECT * FROM domains WHERE customer_id=? ORDER BY id DESC');$st->execute([$c['id']]);$rows=$st->fetchAll();}catch(Throwable $e){} ?>
<?php if($flash): ?><div class="cp-alert <?= e($flash['type']) ?>"><?= e($flash['message']) ?></div><?php endif; ?>
<div class="customer-panel-card"><h2>Domainlerim</h2><p>Domain yenileme, nameserver, DNS, kilit, EPP ve transfer işlemlerinizi buradan yönetin.</p><div class="button-row"><a class="cp-btn" href="<?= url('domain') ?>">Yeni Domain Sorgula</a></div></div>
<div class="customer-panel-card"><table class="table-like"><tr><th>Domain</th><th>Registrar</th><th>Durum</th><th>Bitiş Tarihi</th><th>Kilit</th><th>Oto Yenileme</th><th>İşlem</th></tr><?php foreach($rows as $r): ?><tr><td><strong><?= e($r['domain_name']) ?></strong></td><td><?= e($r['registrar'] ?? ($r['registrar_name'] ?? (!empty($r['registrar_id']) ? ('Registrar #'.(int)$r['registrar_id']) : 'DomainNameAPI'))) ?></td><td><?= e($r['status']) ?></td><td><?= e($r['expiry_date']) ?></td><td><?= $r['lock_status']?'Kilitli':'Açık' ?></td><td><?= $r['auto_renew']?'Açık':'Kapalı' ?></td><td><a class="cp-btn small" href="<?= url('client/domains/view?id='.(int)$r['id']) ?>">Yönet</a></td></tr><?php endforeach; if(!$rows): ?><tr><td colspan="7">Domain kaydı yok.</td></tr><?php endif; ?></table></div>
